/* ═══════════════════════════════════════════════════════════════════════════
   MobileAccountPage — Settings + emergency controls for iOS
   Kill switch, bot status, subscription info, and app settings.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import { useTheme } from '../contexts/ThemeContext';
import usePageTitle from '../hooks/usePageTitle';
import { usePullToRefresh } from '@/hooks/usePullToRefresh';
import { tokens } from '../styles/tokens';
import s from './MobileAccountPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const BOT_NAMES = ['SHAWN', 'SHANE', 'NOVA'];

const TIER_BADGES = {
  explorer:       { label: 'Explorer', color: '#8899AA', bg: 'rgba(136,153,170,0.10)' },
  trader:         { label: 'Trader', color: '#58A6FF', bg: 'rgba(88,166,255,0.10)' },
  pro:            { label: 'Pro', color: '#A78BFA', bg: 'rgba(167,139,250,0.10)' },
  institutional:  { label: 'Institutional', color: '#F59E0B', bg: 'rgba(245,158,11,0.10)' },
  ultra:          { label: 'ULTRA', color: '#3FB950', bg: 'rgba(63,185,80,0.10)' },
};

function getTierBadge(tier) {
  const key = (tier || 'explorer').toLowerCase();
  return TIER_BADGES[key] || TIER_BADGES.explorer;
}

function timeAgo(ts) {
  if (!ts) return 'Never';
  const diff = Date.now() - new Date(ts).getTime();
  if (diff < 60000) return 'Just now';
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  return `${Math.floor(diff / 86400000)}d ago`;
}

/* ── Toggle Switch ── */
function ToggleSwitch({ checked, onChange, disabled }) {
  return (
    <button
      className={`${s.toggle} ${checked ? s.toggleOn : s.toggleOff}`}
      onClick={() => !disabled && onChange(!checked)}
      disabled={disabled}
      role="switch"
      aria-checked={checked}
    >
      <div className={s.toggleThumb} />
    </button>
  );
}

/* ── Kill Switch Confirmation Dialog ── */
function KillConfirmDialog({ onConfirm, onCancel }) {
  return (
    <div className={s.confirmOverlay} onClick={onCancel}>
      <div className={s.confirmDialog} onClick={e => e.stopPropagation()}>
        <div className={s.confirmIcon}>!</div>
        <h3 className={s.confirmTitle}>Emergency Stop All Trading</h3>
        <p className={s.confirmText}>
          This will immediately halt all bot execution across every engine and broker connection.
          All open orders will be cancelled. Active positions will be held but no new trades will execute.
        </p>
        <p className={s.confirmWarning}>This action cannot be undone from mobile.</p>
        <div className={s.confirmActions}>
          <button className={s.confirmCancel} onClick={onCancel}>Cancel</button>
          <button className={s.confirmKill} onClick={onConfirm}>KILL ALL TRADING</button>
        </div>
      </div>
    </div>
  );
}

/* ── Bot Status Row ── */
function BotStatusRow({ name, status, equity, lastHeartbeat }) {
  const isActive = status === 'OK' || status === 'ACTIVE' || status === 'RUNNING';
  return (
    <div className={s.botRow}>
      <div className={s.botRowLeft}>
        <div className={s.botStatusDot} style={{
          background: isActive ? C.green : C.red,
          boxShadow: `0 0 8px ${isActive ? 'rgba(63,185,80,0.5)' : 'rgba(248,81,73,0.5)'}`,
        }} />
        <div>
          <div className={s.botName}>{name}</div>
          <div className={s.botHeartbeat}>Last: {timeAgo(lastHeartbeat)}</div>
        </div>
      </div>
      <div className={s.botRowRight}>
        <div className={s.botEquity}>
          {equity != null ? `$${Number(equity).toLocaleString('en-US', { maximumFractionDigits: 0 })}` : '--'}
        </div>
        <div className={s.botStatusLabel} style={{ color: isActive ? C.green : C.red }}>
          {isActive ? 'ACTIVE' : status || 'OFFLINE'}
        </div>
      </div>
    </div>
  );
}

/* ── Main Page ── */
export default function MobileAccountPage() {
  usePageTitle('Account');
  const navigate = useNavigate();
  const { themeKey, setTheme } = useTheme();
  const [health, setHealth] = useState(null);
  const [telemetry, setTelemetry] = useState(null);
  const [killActive, setKillActive] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [killLoading, setKillLoading] = useState(false);
  const [notifications, setNotifications] = useState(true);
  const [loading, setLoading] = useState(true);
  const actionInProgress = useRef(false);

  // User info from localStorage
  const user = (() => {
    try { return JSON.parse(localStorage.getItem('aura_user') || '{}'); } catch { return {}; }
  })();
  const userTier = user.tier || user.subscription_tier || 'explorer';
  const tierBadge = getTierBadge(userTier);

  const fetchData = useCallback(async () => {
    try {
      const [healthData, telData] = await Promise.all([
        api('/control/health', { silent: true }),
        api('/telemetry/latest', { silent: true }),
      ]);
      if (healthData) {
        setHealth(healthData);
        if (!actionInProgress.current) {
          setKillActive(healthData.killSwitch === true || healthData.kill_switch === true || healthData.killed === true);
        }
      }
      if (telData) setTelemetry(telData);
    } catch { /* handled */ }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
    const id = setInterval(fetchData, 5000);
    return () => clearInterval(id);
  }, [fetchData]);

  usePullToRefresh(fetchData);

  // Extract bot data from telemetry
  const getBotInfo = (name) => {
    const bots = telemetry?.bots || {};
    const key = Object.keys(bots).find(k => k.toUpperCase() === name.toUpperCase());
    const info = key ? bots[key] : {};
    const payload = info?.payload || {};
    const eq = payload.equity || {};
    return {
      status: info?.status || 'UNKNOWN',
      equity: eq.current ?? eq.total ?? null,
      lastHeartbeat: info?.last_heartbeat || null,
    };
  };

  // Kill switch handler
  const handleKill = async () => {
    setShowConfirm(false);
    setKillLoading(true);
    actionInProgress.current = true;
    try {
      const result = await apiPost('/control/kill', { action: 'kill' });
      if (result) {
        setKillActive(true);
      }
    } catch { /* handled */ }
    setKillLoading(false);
    // Keep actionInProgress true for a bit to avoid poll overwrite
    setTimeout(() => { actionInProgress.current = false; }, 3000);
  };

  // Resume handler
  const handleResume = async () => {
    setKillLoading(true);
    actionInProgress.current = true;
    try {
      const result = await apiPost('/control/kill', { action: 'resume' });
      if (result) {
        setKillActive(false);
      }
    } catch { /* handled */ }
    setKillLoading(false);
    setTimeout(() => { actionInProgress.current = false; }, 3000);
  };

  const handleSignOut = () => {
    localStorage.removeItem('aura_token');
    localStorage.removeItem('aura_refresh_token');
    localStorage.removeItem('aura_user');
    navigate('/login');
  };

  const isDark = themeKey === 'night' || themeKey === 'midnight' || themeKey === 'deep_space';

  if (loading) {
    return (
      <div className={s.page}>
        <div className={s.loadingWrap}>
          <div className={s.spinner} />
          <div className={s.loadingText}>Loading account...</div>
        </div>
      </div>
    );
  }

  return (
    <div className={s.page}>
      {/* ─── Section 1: Kill Switch ─── */}
      <div className={`${s.card} ${s.killCard}`}>
        <div className={s.killStatus}>
          <div className={s.killStatusDot} style={{
            background: killActive ? C.red : C.green,
            boxShadow: `0 0 12px ${killActive ? 'rgba(248,81,73,0.6)' : 'rgba(63,185,80,0.6)'}`,
          }} />
          <span className={s.killStatusText} style={{ color: killActive ? C.red : C.green }}>
            All bots: {killActive ? 'KILLED' : 'ACTIVE'}
          </span>
        </div>

        {!killActive ? (
          <button
            className={s.killButton}
            onClick={() => setShowConfirm(true)}
            disabled={killLoading}
          >
            {killLoading ? 'Processing...' : 'EMERGENCY STOP ALL TRADING'}
          </button>
        ) : (
          <button
            className={s.resumeButton}
            onClick={handleResume}
            disabled={killLoading}
          >
            {killLoading ? 'Processing...' : 'RESUME TRADING'}
          </button>
        )}
      </div>

      {/* ─── Section 2: Bot Status ─── */}
      <div className={s.card}>
        <div className={s.cardHeader}>
          <h2 className={s.cardTitle}>Bot Status</h2>
        </div>

        {BOT_NAMES.map(name => {
          const info = getBotInfo(name);
          return (
            <BotStatusRow
              key={name}
              name={name}
              status={info.status}
              equity={info.equity}
              lastHeartbeat={info.lastHeartbeat}
            />
          );
        })}

        {/* Also show any additional bots from telemetry */}
        {telemetry?.bots && Object.keys(telemetry.bots)
          .filter(k => !BOT_NAMES.includes(k.toUpperCase()) && !['layla', 'paper', 'demo'].includes(k.toLowerCase()) && typeof telemetry.bots[k] === 'object' && telemetry.bots[k]?.status)
          .map(name => {
            const info = getBotInfo(name);
            return (
              <BotStatusRow
                key={name}
                name={name.toUpperCase()}
                status={info.status}
                equity={info.equity}
                lastHeartbeat={info.lastHeartbeat}
              />
            );
          })
        }
      </div>

      {/* ─── Section 3: Subscription ─── */}
      <div className={s.card}>
        <div className={s.cardHeader}>
          <h2 className={s.cardTitle}>Subscription</h2>
        </div>

        <div className={s.tierRow}>
          <div className={s.tierBadge} style={{ background: tierBadge.bg, color: tierBadge.color }}>
            {tierBadge.label}
          </div>
          <span className={s.tierLabel}>Current Plan</span>
        </div>

        {userTier !== 'institutional' && userTier !== 'ultra' && (
          <>
            <button className={s.upgradeBtn} onClick={() => navigate('/pricing')}>
              Upgrade Plan
            </button>
            <div className={s.upgradeTeaser}>
              {userTier === 'explorer' && 'Unlock live trading, real-time signals, and AI insights.'}
              {userTier === 'trader' && 'Unlock ULTRA signals with 100% precision and priority execution.'}
              {userTier === 'pro' && 'Go Institutional: unlimited strategies, dedicated support, custom models.'}
            </div>
          </>
        )}
      </div>

      {/* ─── Section 4: Settings ─── */}
      <div className={s.card}>
        <div className={s.cardHeader}>
          <h2 className={s.cardTitle}>Settings</h2>
        </div>

        {/* Notifications */}
        <div className={s.settingRow}>
          <div className={s.settingInfo}>
            <div className={s.settingLabel}>Push Notifications</div>
            <div className={s.settingDesc}>Alerts for signals, fills, and risk events</div>
          </div>
          <ToggleSwitch checked={notifications} onChange={setNotifications} />
        </div>

        {/* Dark / Light */}
        <div className={s.settingRow}>
          <div className={s.settingInfo}>
            <div className={s.settingLabel}>Dark Mode</div>
            <div className={s.settingDesc}>Switch between dark and light themes</div>
          </div>
          <ToggleSwitch
            checked={isDark}
            onChange={(val) => setTheme(val ? 'night' : 'day')}
          />
        </div>

        {/* Broker status */}
        <div className={s.settingRow}>
          <div className={s.settingInfo}>
            <div className={s.settingLabel}>Connected Broker</div>
            <div className={s.settingDesc}>
              {health?.gateway_connected ? 'IBKR Gateway connected' : 'Not connected'}
            </div>
          </div>
          <div className={s.brokerDot} style={{
            background: health?.gateway_connected ? C.green : C.red,
            boxShadow: `0 0 6px ${health?.gateway_connected ? 'rgba(63,185,80,0.4)' : 'rgba(248,81,73,0.4)'}`,
          }} />
        </div>

        {/* Sign out */}
        <button className={s.signOutBtn} onClick={handleSignOut}>
          Sign Out
        </button>
      </div>

      {/* ─── Kill Confirm Dialog ─── */}
      {showConfirm && (
        <KillConfirmDialog
          onConfirm={handleKill}
          onCancel={() => setShowConfirm(false)}
        />
      )}
    </div>
  );
}
